import{_ as e,o as a,c as i,a2 as o}from"./chunks/framework.B08aFN1B.js";const u=JSON.parse('{"title":"Cell tags & caching","description":"","frontmatter":{},"headers":[],"relativePath":"cell-tags.md","filePath":"cell-tags.md","lastUpdated":null}'),r={name:"cell-tags.md"};function s(l,t,n,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="Cell-tags-and-caching" tabindex="-1">Cell tags &amp; caching <a class="header-anchor" href="#Cell-tags-and-caching" aria-label="Permalink to &quot;Cell tags &amp; caching {#Cell-tags-and-caching}&quot;">​</a></h1><p>Every cell carries a small set of <strong>tags</strong> in its <code>#%%</code> header. Tags change how a cell behaves, how it renders, and what role it plays in a document. Set them with the <strong>🏷</strong> button in the cell header (a small tag editor), or type a token directly into the header.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#%% code id=setup collapsed        ← a `collapsed` behaviour tag in the header</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LinearAlgebra, Statistics</span></span></code></pre></div><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/tag-editor.png" alt=""></p><h2 id="Behaviour-tags" tabindex="-1">Behaviour tags <a class="header-anchor" href="#Behaviour-tags" aria-label="Permalink to &quot;Behaviour tags {#Behaviour-tags}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tag</th><th style="text-align:right;">Effect</th></tr></thead><tbody><tr><td style="text-align:right;"><code>collapsed</code></td><td style="text-align:right;">Fold the cell (hide it in the notebook; omitted from slide/report export).</td></tr><tr><td style="text-align:right;"><code>hidecode</code></td><td style="text-align:right;">Hide the editor, show only the output — a clean result without the source.</td></tr><tr><td style="text-align:right;"><code>trace</code></td><td style="text-align:right;">Wrap the cell in <code>@trace</code> — collect every intermediate value into a trace table (also the cell&#39;s 🔍 button). See <a href="/KaimonSlate.jl/dev/cell-tags#tracing">Tracing</a>.</td></tr><tr><td style="text-align:right;"><code>nocache</code></td><td style="text-align:right;">Opt <strong>out</strong> of durable memoization — for impure / side-effecting cells that must re-run. See <a href="/KaimonSlate.jl/dev/cell-tags#caching">Caching</a>.</td></tr></tbody></table><h2 id="Presentation-tags" tabindex="-1">Presentation tags <a class="header-anchor" href="#Presentation-tags" aria-label="Permalink to &quot;Presentation tags {#Presentation-tags}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tag</th><th style="text-align:right;">Effect</th></tr></thead><tbody><tr><td style="text-align:right;"><code>slide</code></td><td style="text-align:right;">Force a new <a href="./slides">slide</a> at this cell, regardless of headings.</td></tr><tr><td style="text-align:right;"><code>notes</code></td><td style="text-align:right;">Speaker notes — attached to the current slide, shown only in presenter/notes output.</td></tr></tbody></table><h2 id="Document-role-tags" tabindex="-1">Document-role tags <a class="header-anchor" href="#Document-role-tags" aria-label="Permalink to &quot;Document-role tags {#Document-role-tags}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tag</th><th style="text-align:right;">Effect</th></tr></thead><tbody><tr><td style="text-align:right;"><code>title</code></td><td style="text-align:right;">This cell is the document <a href="/KaimonSlate.jl/dev/documents#front-matter">title block</a>.</td></tr><tr><td style="text-align:right;"><code>abstract</code></td><td style="text-align:right;">This cell is the academic abstract.</td></tr><tr><td style="text-align:right;"><code>bibliography</code></td><td style="text-align:right;">This cell is the <a href="/KaimonSlate.jl/dev/documents#bibliography">bibliography</a> (BibTeX or <code>.bib</code> paths).</td></tr></tbody></table><h2 id="Site-tags" tabindex="-1">Site tags <a class="header-anchor" href="#Site-tags" aria-label="Permalink to &quot;Site tags {#Site-tags}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tag</th><th style="text-align:right;">Effect</th></tr></thead><tbody><tr><td style="text-align:right;"><code>home</code></td><td style="text-align:right;">This notebook is the published <a href="/KaimonSlate.jl/dev/publishing#front-page-and-document-listing">site&#39;s front page</a>.</td></tr><tr><td style="text-align:right;"><code>docindex</code></td><td style="text-align:right;">Marks where the site&#39;s document listing is injected on a <code>home</code> notebook.</td></tr></tbody></table><p>Any other token is a <strong>free-form tag</strong> that simply round-trips in the <code>.jl</code> header — useful for your own grouping or tooling.</p><h2 id="tracing" tabindex="-1">Tracing <a class="header-anchor" href="#tracing" aria-label="Permalink to &quot;Tracing&quot;">​</a></h2><p>Tagging a cell <code>trace</code> (or clicking its 🔍 button) wraps it in <code>@trace</code>: each line&#39;s value is collected into a <strong>trace table</strong> you can open and inspect, so you can see every intermediate without scattering <code>@show</code>. You can also write <code>@trace begin … end</code> by hand around part of a cell.</p><h2 id="caching" tabindex="-1">Caching <a class="header-anchor" href="#caching" aria-label="Permalink to &quot;Caching&quot;">​</a></h2><p>KaimonSlate durably <strong>memoizes</strong> cell results to disk: a cell that takes more than a moment (about 150 ms) is cached automatically, keyed by its source and inputs, and <strong>restored</strong> instead of recomputed after a worker restart or when you reopen the notebook. Two tags tune it:</p><ul><li><p><strong><code>cache</code></strong> — force a cell&#39;s result to persist regardless of runtime, for a deterministic pipeline stage whose inputs rarely change.</p></li><li><p><strong><code>nocache</code></strong> — opt out, for impure or side-effecting cells (randomness you want fresh, network calls) where a restored value would be wrong. It also stops everything downstream from being restored, since they depend on a value that must re-run.</p></li></ul><div class="tip custom-block"><p class="custom-block-title">Structure for the cache</p><p>Put an expensive computation (a simulation, a large read, a fit) in its <strong>own</strong> cell so its result is cached independently of the cheap cells that render it. The reactive engine already recomputes only what changed; the cache makes that survive restarts.</p></div><p>See <strong><a href="./memoization">Memoization &amp; Caching</a></strong> for the full model — the content-addressed store, cache keys, restore, display-object elision, and the Arrow/typed codecs.</p>',20)])])}const p=e(r,[["render",s]]);export{u as __pageData,p as default};
